insert into public.knowledge_entries
  (type, title, body, category, tags, source_type, source_id, source_title, status, confidence, created_by)
values
('term','APS(Attending Physician Statement, 주치의 소견서)','보험회사가 계약심사(언더라이팅) 과정에서 청약자의 기왕증 또는 건강 상태를 심층 파악하기 위해 해당 의사 또는 의료기관에 직접 요청하는 서면 소견서. 청약서 및 건강진단 결과만으로 위험 판단이 불충분할 때 추가 심사 자료로 활용된다. 피보험자 동의를 전제로 하며, 주치의·진료 의사가 치료 경위·현재 상태·예후 등을 기재한다. 국내외 생명보험 언더라이팅 실무에서 광범위하게 사용된다.','인수',array['APS','주치의소견서','언더라이팅','계약심사','의무기록','인수심사'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 민영건강보험의 언더라이팅 선진화 방안(re2003-01) — kiri.or.kr 원문 PDF 확인','ai_draft','medium','admin'),
('term','표준화(Standardization) 인수 — 재심사(Re-underwriting)','최초 인수 시 조건부 승인(할증·부담보 등)으로 처리된 계약에 대해 일정 기간 경과 후 또는 피보험자의 건강 상태 변화를 이유로 표준체 조건으로 재전환을 심사하는 절차. 생명보험 실무에서는 계약자가 병력 완치·관해 확인서류를 제출하면 보험회사가 재심사를 진행한다. 상법상 별도 명문 규정은 없으나 보험업감독업무시행세칙 [별표14] 표준사업방법서 및 각 사 내규에서 운용한다.','인수',array['재심사','표준화인수','할증해제','부담보해제','조건부승인'],'cycle2_supp','cycle2_supp','보험업감독업무시행세칙 [별표14] 표준사업방법서(금융감독원, law.go.kr 수록); 보험연구원(KIRI) 민영건강보험의 언더라이팅 선진화 방안(re2003-01)','ai_draft','medium','admin'),
('term','고위험 청약 특별인수심사(Special Underwriting for High-risk Applications)','보험가입금액이 일정 기준을 초과하거나 단기간 집중 가입, 역선택 징후 등 고위험 신호가 있는 청약 건에 대해 일반 심사보다 강화된 절차를 적용하는 제도. 생명보험협회·손해보험협회 「중복·과다 보험가입 방지 인수심사 가이드라인」(2023.9.1 시행)에 의거, 보험회사는 피보험자의 연령대별 소득상실 추정액 대비 배수를 고려해 인수 기준을 마련한다. 취약계층에 대한 담보액 감액 인수 조항도 포함된다.','인수',array['고위험청약','특별인수심사','역선택방지','집중가입','인수기준강화'],'cycle2_supp','cycle2_supp','생명보험협회·손해보험협회 「중복·과다 보험가입 방지 인수심사 가이드라인」(2023.9.1 시행); KIRI 보험법 동향 15호(kiri.or.kr 수록)','ai_draft','high','admin'),
('term','사전언더라이팅(Pre-underwriting / Pre-screening)','청약서 공식 접수·서명 이전에 고객이 입력한 건강 고지 내용을 기반으로 보험회사가 사전에 인수 가능 여부 및 예상 조건을 안내하는 절차. 청약 후 심사 지연 및 사후 거절에 따른 소비자 불만을 줄이기 위해 도입됐으며, 한화생명·iM라이프 등 국내 보험사들이 AI·디지털 기술과 결합해 즉시 결과를 제공하는 방향으로 도입·확대하고 있다. 청약 전 단계이므로 계약 효력은 발생하지 않는다.','인수',array['사전언더라이팅','pre-screening','청약전심사','AI언더라이팅','인수가능여부'],'cycle2_supp','cycle2_supp','한국보험신문 「보험사, 고객 편의 위한 사전·가상 언더라이팅 도입 경쟁」(insnews.co.kr); 메트로서울 「보험심사 더 간단하게」(metroseoul.co.kr, 2024.5)','ai_draft','medium','admin'),
('term','계약 후 알릴 의무(통지의무) 위반과 보험료 비례 정산','피보험자가 직업·직무 변경 등 위험 증가 사실을 보험회사에 즉시 통지하지 않은 경우(상법 제652조), 보험회사는 사고 발생 시 변경 전 요율과 변경 후 요율의 비율에 따라 보험금을 비례 지급할 수 있다(약관 규정에 따름). 또한 통지 접수 후 1개월 이내에 보험료 증액을 청구하거나 계약을 해지할 수 있다. 직업 변경 미통지가 가장 빈번한 분쟁 유형이며, 금감원 분쟁조정 선례가 다수 존재한다.','인수',array['통지의무위반','계약후알릴의무','보험료비례정산','직업변경통지','상법652조'],'cycle2_supp','cycle2_supp','상법 제652조(위험변경증가의 통지와 계약해지) — 국가법령정보센터(law.go.kr) 조문 및 판례 확인; 금감원 파인(fine.fss.or.kr) 보험 기본사항 안내','ai_draft','high','admin'),
('term','위험보유한도(Retention Limit)와 최적 출재비율','보험회사가 단일 위험(1건)에 대해 자기 부담으로 보유할 수 있는 최대 금액. 이를 초과하는 위험은 재보험으로 출재한다. 보험업감독규정(금융감독원 소관)에서 재보험 관리기준을 정하고 있으며, 보유한도 초과 위험을 방치하면 RBC(지급여력비율)에 악영향을 미친다. 최적 출재비율은 재보험비용과 자기자본비용의 합이 최소화되는 지점에서 결정된다.','인수',array['위험보유한도','출재비율','자기보유한도','재보험관리기준','RBC'],'cycle2_supp','cycle2_supp','보험업감독규정(금융위원회 고시, law.go.kr 수록); KIRI 재보험 출재전략 연구(nre2019-1212, kiri.or.kr 원문 확인)','ai_draft','medium','admin'),
('term','임의재보험(Facultative Reinsurance)과 특약재보험(Treaty Reinsurance) 선택 기준','임의재보험은 원수보험계약 건별로 재보험자와 개별 협상하여 계약하는 방식으로, 특약재보험의 한도를 초과하거나 특수·거대 위험 인수 시 활용한다. 특약재보험은 사전 협약에 따라 일정 범위 내 모든 계약을 자동 출재한다. 언더라이팅 실무에서는 자동인수한도(Auto-bind limit) 이하는 특약, 초과분은 임의재보험 또는 거절 처리하는 병행 운용이 일반적이다.','인수',array['임의재보험','특약재보험','자동인수한도','출재방법','거대위험'],'cycle2_supp','cycle2_supp','KIRI 재보험 이해 및 현황(nre2019-1212) — kiri.or.kr PDF 원문 확인; KIRI KiRi Weekly 손해보험의 이해 6: 위험의 보유와 재보험(2012.6, kiri.or.kr 수록)','ai_draft','high','admin'),
('term','초과손해액재보험(Excess of Loss Reinsurance, XL)','비비례재보험의 핵심 형태로, 출재사의 보유한도(Retention)를 초과하는 손해액에 대해 재보험자가 책임지는 구조. ''위험당 XL(Working XL)'', ''사고당 XL(Catastrophe XL)'', ''초과손해율 XL(Stop Loss)'' 등으로 세분된다. 거대재해 리스크 분산에 효과적이며, 특약재보험의 비비례 방식으로 운용된다. 손보사 대형화재·풍수해 대비 필수 수단이다.','인수',array['초과손해액재보험','XL재보험','비비례재보험','CatXL','거대재해분산'],'cycle2_supp','cycle2_supp','KIRI 재보험 이해 및 현황(nre2019-1212) 부록 Stop Loss Reinsurance 이론(kiri.or.kr PDF 직접 확인); KIRI KiRi Weekly 손해보험의 이해 6: 위험의 보유와 재보험(2012.6)','ai_draft','high','admin'),
('term','할증보험료 산출 — 여명(餘命) 기준 방식','표준미달체(Substandard Risk)에 대한 생명보험 할증 시, 피보험자의 잔여 기대여명이 동령 표준체보다 단축된 정도를 기준으로 추가보험료를 산출하는 계리 방식. 사망률을 일정 배율(예: 150%, 200%)로 할증하거나 가입나이를 연장(Age Rating)하는 방법이 있다. 생명보험 요율산출 기준서 및 보험료·책임준비금 산출방법서(보험업법 시행령 제7조의2)에서 요율 산출 원칙을 정한다.','인수',array['표준미달체할증','여명기준','사망률할증','연령할인할증','계리언더라이팅'],'cycle2_supp','cycle2_supp','보험업법 시행령 제7조의2(보험료 및 책임준비금 산출방법) — 국가법령정보센터(law.go.kr); 보험업감독업무시행세칙 별표14 표준사업방법서(금융감독원)','ai_draft','high','admin'),
('term','혼합 조건부 인수(Combined Conditional Acceptance)','인수 시 할증보험료 부과와 특정 신체부위·질병 부담보를 동시에 적용하는 인수 결과 유형. 단순 할증이나 단순 부담보만으로는 위험을 충분히 반영하기 어려운 복합 병력 청약자에게 적용한다. 생명보험 표준사업방법서(보험업감독업무시행세칙 별표14)에서 조건부 승낙 유형으로 규정하며, 언더라이터는 할증률과 부담보 부위·기간을 개별 결정한다.','인수',array['혼합조건부인수','할증부담보병행','복합병력','조건부승낙유형','언더라이터결정'],'cycle2_supp','cycle2_supp','보험업감독업무시행세칙 별표14 표준사업방법서(금융감독원 보험심사팀) — 국가법령정보센터(law.go.kr)','ai_draft','high','admin'),
('term','신용정보 활용 언더라이팅(Credit-based Underwriting)','보험회사가 피보험자의 신용정보(보험계약 정보, 보험금 지급 이력 등)를 한국신용정보원에서 조회하여 인수심사에 활용하는 방식. 동의를 전제로 하며, 과거 보험사기 이력, 단기간 다수 가입 이력, 보험금 청구 집중도 등을 파악하는 데 사용된다. 신용정보의 이용 및 보호에 관한 법률(신용정보법)·보험업법에 근거한다.','인수',array['신용정보언더라이팅','보험신용정보','한국신용정보원','인수심사정보조회','보험사기이력'],'cycle2_supp','cycle2_supp','신용정보의 이용 및 보호에 관한 법률 — 국가법령정보센터(law.go.kr); 한국신용정보원 공식 안내(kcredit.or.kr)','ai_draft','high','admin'),
('term','계약전 알릴 의무 고지 범위 — 표준·건강·간편고지 3유형','보험 청약서의 고지 항목 범위에 따라 세 유형으로 분류된다. 1) 표준고지형: 일반적 청약서로 3개월 이내 진단·투약, 1년 이내 추가검사, 5년 이내 입원·수술·30일 이상 투약, 5년 이내 10대 질병 등을 고지. 2) 건강고지형: 표준형보다 고지 항목 확대. 3) 간편고지형(유병자보험): 고지 항목 대폭 축소. 보험업감독업무시행세칙 별표14에서 고지사항 기준을 규정한다.','인수',array['계약전알릴의무','고지범위','표준고지','간편고지','건강고지','별표14'],'cycle2_supp','cycle2_supp','보험업감독업무시행세칙 별표14 표준사업방법서(금융감독원) — 국가법령정보센터(law.go.kr); 금감원 금융꿀팁 보험계약 전 알릴의무 안내','ai_draft','medium','admin'),
('term','태아 주수별 인수 제한(Fetal Gestational Age Underwriting Limit)','태아보험(출생 전 가입 보험)의 인수 가능 주수 상한을 정한 기준. 손해보험은 임신 직후부터 22주(일부 23주) 이내, 생명보험은 통상 임신 16주부터 22주 이내 가입을 허용한다. 기형아 검사(NT 검사, 정밀초음파) 결과에 이상 소견이 발견되기 전에 가입해야 선천성 질환 담보를 확보할 수 있다. 쌍둥이 임신, 인공수정 임신의 경우 별도 서류 심사를 거친다.','인수',array['태아보험인수','임신주수제한','태아특약','선천성질환담보','기형아검사전가입'],'cycle2_supp','cycle2_supp','찾기쉬운 생활법령정보(easylaw.go.kr) 임산부·태아보험 가입 항목','ai_draft','medium','admin'),
('term','비례보상(Proportional Compensation) — 통지의무 위반 시','피보험자가 위험 증가 사실을 통지하지 않아 보험료가 과소납부된 상태에서 보험사고가 발생한 경우, 보험회사가 실제 납부 보험료와 납부했어야 할 보험료의 비율에 따라 보험금을 지급하는 방식. 상법 제652조 통지의무 위반의 효과로 계약 해지 대신 보험금 비례 감액이 적용되는 실무 처리 방식이다. 직업 위험 급수 변경 미통지 분쟁에서 빈번히 적용된다.','보장',array['비례보상','통지의무위반','보험금감액','직업변경비례지급','상법652조'],'cycle2_supp','cycle2_supp','상법 제652조(위험변경증가의 통지와 계약해지) — 국가법령정보센터(law.go.kr); 대법원 판례속보 통지의무 위반 관련 사건(scourt.go.kr)','ai_draft','high','admin'),
('term','출재사(Ceding Company)와 수재사(Assuming/Reinsuring Company)','출재사는 자신의 원수보험계약 위험을 재보험자에게 이전하는 보험회사이며, 수재사(재보험회사)는 그 위험을 인수하는 회사이다. 출재사가 지급하는 재보험료(Reinsurance Premium)에서 수재사가 환급하는 재보험수수료(Ceding Commission)를 차감한 순비용이 출재비용이다. 국내 보험업감독규정에서 출재·수재 비율과 재보험 계약 체결 기준을 정한다.','인수',array['출재사','수재사','재보험료','재보험수수료','출재비용'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 재보험 이해 및 현황(nre2019-1212) — kiri.or.kr','ai_draft','high','admin'),
('term','포트폴리오 언더라이팅(Portfolio Underwriting) — 위험집중 관리','개별 계약 단위 심사를 넘어, 보험회사 전체 계약 포트폴리오 차원에서 특정 지역·업종·피보험자 특성에 위험이 집중되지 않도록 관리하는 언더라이팅 전략. 지역 집중(Geographical Concentration), 업종 집중, 특정 연령층 집중 등을 모니터링한다. 손해보험 화재·자연재해 분야에서 특히 중요하며, 위험집중 지역 신규 인수 제한 결정도 이에 해당한다.','인수',array['포트폴리오언더라이팅','위험집중관리','지역집중','언더라이팅전략','손해보험'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 일반손해보험과 언더라이팅 연구(josa_15_07_02) — kiri.or.kr','ai_draft','medium','admin'),
('term','계약적부확인(Post-issue Underwriting / Field Underwriting Audit)','보험계약 승낙 후 계약의 실질적 유효성과 청약서 기재 내용의 진실성을 현장 또는 서류 조사를 통해 검증하는 절차. 고액계약, 단기 집중가입, 피보험자 미면접 계약 등에서 실시하며, 모럴해저드 및 보험사기 방지가 주목적이다. 생명보험 실무에서는 계약 체결 직후 현장 확인(Field Inspection)을 수행하기도 한다. 보험업감독업무시행세칙 표준사업방법서에 관련 기준이 반영된다.','인수',array['계약적부확인','사후언더라이팅','현장조사','보험사기방지','고액계약심사'],'cycle2_supp','cycle2_supp','보험연구원(KIRI) 일반손해보험과 언더라이팅 연구(josa_15_07_02) — kiri.or.kr; 보험업감독업무시행세칙(금융감독원) — 국가법령정보센터(law.go.kr)','ai_draft','high','admin'),
('term','부담보 기간 유형 — 전기간·한시·특정사고 부담보','부담보 처리 방식은 적용 기간과 범위에 따라 세분된다. 1) 전기간 부담보: 계약 기간 전체에 걸쳐 특정 부위·질병 보장 제외. 2) 한시(限時) 부담보: 일정 기간(예: 1년, 2년)만 부담보 적용 후 표준체 전환. 3) 특정사고 부담보: 특정 원인(예: 기왕증으로 인한 재발)에 한해 부담보. 생명보험 표준사업방법서 및 각 보험사 인수지침에서 유형별 적용 기준을 정한다.','인수',array['전기간부담보','한시부담보','특정사고부담보','부담보유형','인수조건'],'cycle2_supp','cycle2_supp','보험업감독업무시행세칙 별표14 표준사업방법서(금융감독원) — 국가법령정보센터(law.go.kr)','ai_draft','high','admin'),
('term','인수 거절 사유 통보 의무와 소비자 권리','보험회사가 청약을 거절하는 경우, 상법 제638조의2에 따라 보험료 납입과 함께 청약을 받은 날로부터 30일 이내에 승낙 또는 거절 통보를 발송해야 한다. 30일 내 미통보 시 승낙 간주. 다만 ''거절 시 사유를 구체적으로 알릴 의무''는 동 조항에 명시되어 있지 않으며, 보험업감독규정상 명시적 의무 조항도 검색 결과에서 확인되지 않는다. 거절 이유를 확인하려는 소비자는 금융소비자보호법 제28조 제3항(자료의 기록 및 유지·관리, 자료열람요구권)을 근거로 분쟁조정 또는 소송 목적의 자료 열람을 요구할 수 있다. 단, 동 조항은 모든 청약 심사 자료 열람을 포괄적으로 보장하는 규정이 아니며 ''분쟁조정 또는 소송 수행 등 권리구제 목적''으로 한정된다.','민원',array['인수거절사유통보','거절사유고지의무','소비자권리','분쟁조정','자료열람요구'],'cycle2_supp','cycle2_supp','상법 제638조의2(보험계약의 성립) — 국가법령정보센터(law.go.kr); 금융소비자 보호에 관한 법률 제28조 제3항(자료열람요구권) — 국가법령정보센터','ai_draft','medium','admin'),
('term','개인정보·건강정보 수집·활용 동의와 철회 — 보험 계약심사','보험회사는 계약심사를 위해 피보험자의 민감정보(건강 정보, 진료 기록 등)를 수집할 때 별도의 명시적 동의를 받아야 한다(개인정보 보호법 제23조, 신용정보법). 동의 철회 시 해당 정보는 원칙적으로 파기되나, 계약 유지를 위해 필요한 최소 정보는 법정 보존기간 동안 보관된다. 보험사는 개인정보처리방침에 건강정보 수집·이용·제공 현황을 공개해야 한다.','계약',array['건강정보동의','민감정보수집','동의철회','개인정보보호법23조','계약심사정보'],'cycle2_supp','cycle2_supp','개인정보 보호법 제23조(민감정보의 처리 제한) — 국가법령정보센터(law.go.kr); KIRI 보험연구원 인슈어테크 발전에 따른 보험신용정보 보호 및 활용(kiri.or.kr)','ai_draft','high','admin'),
('term','자동인수한도(Auto-bind Limit / Automatic Binding Limit)','재보험 특약 계약에서 원수보험사가 재보험사의 별도 승인 없이 자동으로 출재할 수 있는 1건당 최대 책임금액. 이 한도 이내 계약은 특약 조건에 따라 자동 처리되고, 초과분은 임의재보험 협상 또는 언더라이터 직접 심사가 필요하다. 국내 보험업감독규정에서 재보험 관리기준의 일환으로 자동인수한도 설정·관리를 규정한다.','인수',array['자동인수한도','auto-bind','특약재보험한도','재보험관리','언더라이터승인'],'cycle2_supp','cycle2_supp','보험업감독규정(국가법령정보센터 law.go.kr) — 재보험 관리기준 관련 별표; 보험연구원(KIRI) 재보험 관련 연구 자료(kiri.or.kr)','ai_draft','medium','admin'),
('term','일반손해보험 개별물건 요율(Individual Risk Rating)','공장·특수건물 등 기업성 손해보험 계약에서 동질 집단 통계 기반 참조요율 적용이 어려운 경우, 언더라이터가 개별 물건의 구조·소방설비·위험물 보관 여부·손해방지 활동 등을 직접 평가하여 요율을 산출하는 방식. 보험개발원 참조순보험요율을 기준으로 가감요율을 적용한다. 보험업감독규정 제6-4조에서 요율 산출 원칙을 정한다.','인수',array['개별물건요율','기업성손해보험','특수건물','공장언더라이팅','요율산출'],'cycle2_supp','cycle2_supp','보험업감독규정 제6-4조(보험요율 산출원칙) — 국가법령정보센터(law.go.kr); 보험연구원(KIRI) 일반손해보험 언더라이팅 관련 연구자료(kiri.or.kr)','ai_draft','high','admin'),
('term','독립책임액 방식(비례보상 계산법)','실손의료보험 등 손해보험에서 다수 계약이 존재할 때 각 보험사의 지급 책임을 산정하는 방식. 각 계약이 ''단독으로 존재했다면 지급했을 금액(독립책임액)''을 먼저 각각 산출한 뒤, 그 합산액 대비 각 독립책임액의 비율에 따라 실제 손해액을 나누어 보상한다. 상법 제672조(중복보험) 적용 시 주요 계산법 중 하나로 사용되며, 보험사마다 공제기준·한도가 다를 때 각 계약을 별개로 계산하므로 실제 수령액이 단순 비율과 다를 수 있다.','보장',array['독립책임액','비례보상 계산','중복보험 정산','상법672조','다수계약 보상'],'cycle2_supp','cycle2_supp','상법 제672조(중복보험) — 국가법령정보센터(law.go.kr); 클레임손해사정 중복보험 보상방법 해설(claimcare.co.kr)','ai_draft','high','admin'),
('term','4세대 실손보험 비급여 할인·할증 등급제(1~5등급)','2024년 7월 1일부터 시행된 4세대 실손보험의 비급여 보험료 차등제. 갱신 전 1년간 비급여 보험금 수령액에 따라 5단계로 구분한다. 1등급(수령 0원)은 약 5% 할인, 2등급(100만원 미만)은 유지, 3등급(100만원 이상~150만원 미만)은 +100%, 4등급(150만원~300만원)은 +200%, 5등급(300만원 이상)은 +300% 할증. 계약 해당일 3개월 전 말일부터 직전 1년 지급실적 기준으로 산정. 보험사 앱·홈페이지에서 등급 조회 가능. 산정특례 대상 질환(암·심장·뇌혈관·희귀난치) 및 노인장기요양보험법상 장기요양 1·2등급 판정자의 의료비는 할증 등급 산정에서 제외된다.','보장',array['비급여 할인할증','4세대 실손 등급제','비급여 차등보험료','실손 1~5등급'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 ''24.7.1일부터 4세대 실손의료보험 비급여 이용량에 따라 보험료 할인·할증 적용''(fsc.go.kr/po010101/82406)','ai_draft','high','admin'),
('term','실손보험 계약전환 시 무사고 할인 승계','1~3세대 실손보험 가입자가 4세대로 계약전환 시 기존 계약의 무사고 기간도 인정받아 보험료 할인 혜택이 승계된다. 4세대 기준 직전 2년 무사고 시 비급여 특약 보험료의 10% 할인이 적용된다(별도의 비급여 차등제 할인 약 5%와 중복 적용 가능). 전환 후 3개월 이내는 보험금 지급사유 발생 여부와 관계없이 철회 가능하고, 3개월 초과~6개월 이내는 보험금 수령이 없을 경우 철회하여 원계약으로 복귀할 수 있다(무심사 전환 + 철회제도). 단, 전환 전 계약의 보장내용·보험료는 되돌아가므로 전환 전 충분한 비교 검토가 필요.','계약',array['실손 계약전환','무사고 할인 승계','실손 4세대 전환','무심사전환','전환 철회'],'cycle2_supp','cycle2_supp','손해보험협회 실손 전환제도 안내(kpub.knia.or.kr/productDisc/lostHealth/lostHealthMinsInsIntro.do); DB손해보험 4세대 실손 계약전환 할인제도 시행 안내(idbins.com)','ai_draft','medium','admin'),
('term','실손24(실손보험 청구 전산화)','보험업법 개정(2023년 10월 24일 공포, 법률 제19780호)으로 도입된 실손의료보험 청구 전산화 시스템. 요양기관이 청구에 필요한 서류(진료비 영수증·세부내역서 등)를 보험개발원(전송대행기관)을 통해 보험사에 전자적으로 전송한다. 1단계(2024년 10월 25일): 병원급 이상·보건소(약 0.8만개) 대상. 2단계(2025년 10월 25일): 의원·약국까지 확대, 전국 약 10.5만 요양기관 대상. 소비자가 청구하지 않은 진료 정보는 전송 불가(목적 외 정보 집중 금지).','민원',array['실손24','실손보험 청구 전산화','청구간소화법','보험업법 개정','전송대행기관'],'cycle2_supp','cycle2_supp','보험업법 제102조의10 이하(국가법령정보센터 law.go.kr); 금융위원회 보도자료 ''실손보험 청구 전산화 확대 시행''(fsc.go.kr/no010101/85456)','ai_draft','high','admin'),
('term','5세대 실손보험(중증 비급여 특약1·비중증 비급여 특약2 분리 구조)','2026년 5월 6일 출시된 5세대 실손의료보험. 비급여를 중증(특약1)과 비중증(특약2)으로 분리 보장. 특약1(중증 비급여): 산정특례 대상 질환(암·심장·뇌혈관·희귀난치 등) 관련 비급여, 자기부담 30%, 연간 5000만원 한도. 특약2(비중증 비급여): 도수치료·비급여주사 등, 자기부담 50%(통원 시 50%+5만원), 연간 1000만원 한도. 4세대 대비 보험료 약 30% 저렴. 중증 비급여에는 연간 자기부담 상한 500만원 신설로 중증 환자 의료비 과부담 방지.','보장',array['5세대 실손보험','중증 비급여 특약','비중증 비급여 특약','실손보험 개편 2026','비급여 자기부담 50%'],'cycle2_supp','cycle2_supp','금융위원회 보도자료 5세대 실손 출시(fsc.go.kr/no010101/86059); 금융위원회 5세대 실손 상세 보도자료(fsc.go.kr/no010101/86831)','ai_draft','high','admin'),
('term','통원 합산 한도(외래+처방조제 1회 20만원, 연간 180회)','4세대 표준 실손의료보험 기준, 통원의료비는 외래와 처방조제비를 합산하여 1회당 20만원 한도로 보장되며, 입·통원 합산 연간 5000만원을 한도로 한다. 통원 횟수는 연간 180회까지. 같은 날 동일 의료기관에서 외래 진료와 처방조제를 함께 받은 경우 처방일자 기준으로 1회로 합산 처리된다. 공제금액은 종별로 차등(병·의원: 1만원과 의료비의 20% 중 큰 금액; 상급종합·종합병원: 2만원과 20% 중 큰 금액).','보장',array['통원 합산 한도','외래 처방 1회','실손 통원 20만원','연간 180회','통원 공제금액'],'cycle2_supp','cycle2_supp','손해보험협회 실손의료보험(4세대) 표준 공시(kpub.knia.or.kr/productDisc/lostHealth/lostHealth4thStandard.do)','ai_draft','high','admin'),
('term','비급여 의료행위 표준코드(HIRA 비급여 코드 체계)','건강보험심사평가원(HIRA)이 비급여 의료행위 및 치료재료에 부여하는 표준 분류 코드. 비급여 항목 코드를 표준화하여 의료기관 간 비교공시를 가능하게 한다. 실손보험 청구 전산화(실손24)에서 요양기관이 서류를 전송할 때 이 코드가 활용된다. 비급여 진료비용 등의 보고 및 공개에 관한 기준(보건복지부 고시)에 의해 병원급 이상 의료기관은 지정된 항목을 심사평가원에 보고·공개 의무가 있다. 공개 항목 수는 급여 전환 및 삭제 등에 따라 변동되며(과거 616항목에서 현재 578항목 등으로 변경), source 확인 시점의 최신 고시를 기준으로 적용한다.','보장',array['비급여 코드','HIRA 비급여 분류코드','비급여 표준코드','비급여 진료비 공시','심사평가원 비급여'],'cycle2_supp','cycle2_supp','건강보험심사평가원 비급여 의료행위 및 치료재료 코드 표준화 연구(repository.hira.or.kr); 국가법령정보센터 비급여 진료비용 등의 보고 및 공개에 관한 기준(law.go.kr); HIRA 비급여 진료비 정보 안내(hira.or.kr/npay)','ai_draft','medium','admin'),
('term','비급여 진료비 고지 의무(의료법상 사전 설명·게시 의무)','의료법 제45조 및 ''비급여 진료비용 등의 고지 지침''(보건복지부 고시 제2023-192호, 2023.10.25. 시행)에 따라 의료기관은 비급여 대상 제공 전 환자에게 항목·가격을 직접 설명해야 하며, 원내 비치·인터넷 홈페이지 게시 의무가 있다. 병원급 이상은 HIRA 비급여 진료비 정보 포털을 통해 연간 비급여 진료비 현황을 공개한다. 보험사는 이 공개 데이터를 활용해 비급여 보험료 할인·할증의 기초 자료로 활용한다.','보장',array['비급여 진료비 고지 의무','비급여 사전 설명','의료법 비급여 게시','비급여 진료비 공개','HIRA 비급여 포털'],'cycle2_supp','cycle2_supp','의료법 제45조(국가법령정보센터 law.go.kr); 보건복지부 비급여 진료비용 등의 고지 지침(보건복지부 고시 제2023-192호, law.go.kr); HIRA 비급여 정보 포털(hira.or.kr)','ai_draft','high','admin'),
('term','피보험자의 손해사정사 독립 선임권','보험업법 제185조 및 시행령에 따라, 보험회사 소속 손해사정사의 사정 결과에 불복하는 보험계약자·피보험자는 독립 손해사정사를 별도로 선임할 수 있다. 선임 가능 요건: 1) 보험회사 손해사정 결과에 불복하는 경우 2) 보험사고 통보 후 7영업일 경과에도 손해사정 착수 없는 경우(2023년 3영업일에서 10영업일로 확대 개정). 보험회사는 금융위원회가 정한 선임 동의기준 충족 시 반드시 동의해야 한다. 2024년 보험업법 개정(공포 2024.2.6., 시행 2024.8.7.)으로 보험회사 소속 손해사정사 평가 기준에 보험금 삭감 유도 지표 사용 금지 추가.','민원',array['손해사정사 선임권','독립 손해사정사','손해사정 불복','보험업법 185조','손해사정 이의'],'cycle2_supp','cycle2_supp','보험업법 제185조(국가법령정보센터 law.go.kr); 금융위원회 ''보험권의 손해사정 관행이 개선됩니다'' 보도자료(fsc.go.kr); 손해사정 업무위탁 및 손해사정사 선임 등에 관한 모범규준(kcaca.or.kr)','ai_draft','medium','admin'),
('term','본인부담상한제(건강보험 연간 본인부담 상한액 초과 환급)','국민건강보험법 시행령 제19조에 따라 건강보험 가입자가 연간 부담한 요양급여 본인부담금 총액이 소득분위별 상한액을 초과하면 건강보험공단이 초과분을 사후 환급하는 제도. 소득 1~10분위 구간별로 상한액이 다르며(2023년 기준 87만~780만원), 낮은 소득분위일수록 상한액이 낮아 더 많은 환급을 받는다. 비급여·전액 본인부담·선별급여·임플란트·상급병실 2~3인실은 상한액 산정에서 제외. 실손보험과 중복 적용 가능.','보장',array['본인부담상한제','건강보험 상한액 환급','소득분위별 상한','연간 의료비 환급','국민건강보험 환급'],'cycle2_supp','cycle2_supp','국민건강보험공단 본인부담액상한제 안내(nhis.or.kr); 국민건강보험법 시행령 제19조(law.go.kr); 보건복지부 2023년도 본인부담상한액 초과의료비 지급절차 개시 보도자료(mohw.go.kr)','ai_draft','high','admin'),
('term','국민건강보험공단 구상권(제3자 행위에 의한 보험급여 구상)','국민건강보험법 제58조에 따라 건강보험공단은 제3자(교통사고 가해자 등)의 행위로 발생한 보험사고에 급여를 제공한 경우, 급여한 비용 한도 내에서 제3자에 대한 구상권을 취득한다. 구상권 취득 시기는 피보험자가 요양기관에서 치료를 받은 시점. 민간 손해보험사의 보험자대위(상법 제682조)와 유사하나 주체와 근거 법령이 다르다. 대법원 2025.6.5. 중요판결에서 공단 구상권 취득 시기를 재확인.','보장',array['건강보험공단 구상권','제3자 행위 보험급여','국민건강보험법 58조','보험자대위 구분','교통사고 구상권'],'cycle2_supp','cycle2_supp','국민건강보험법 제58조(국가법령정보센터 law.go.kr); 대법원 2025.6.5. 선고 중요판결(scourt.go.kr 판례속보)','ai_draft','high','admin'),
('term','실화책임에 관한 법률(경과실 실화 손해배상 경감)','경과실로 화재를 발생시킨 자(실화자)의 손해배상액을 법원이 감액할 수 있도록 한 법률(법률 제9648호, 2009.5.8. 전면개정). 민법의 일반 불법행위 책임을 그대로 적용하면 실화자에게 과도한 부담이 생길 수 있어 재판상 감액을 허용. 단, 특수건물 소유자는 ''화재로 인한 재해보상과 보험가입에 관한 법률''에 따라 경과실에도 무과실 책임 수준의 배상책임 보험 가입 의무가 있다. 보험설계 시 화재보험 배상책임 특약 가입 필요성의 근거 법령.','보장',array['실화책임법','경과실 화재 배상','실화 손해배상 경감','화재보험 배상책임','특수건물 의무보험'],'cycle2_supp','cycle2_supp','실화책임에 관한 법률(국가법령정보센터 law.go.kr); 화재로 인한 재해보상과 보험가입에 관한 법률(law.go.kr); 법제처 찾기쉬운 생활법령 화재보험(easylaw.go.kr)','ai_draft','high','admin'),
('term','특수건물 신체손해배상 특약부 화재보험 의무가입','''화재로 인한 재해보상과 보험가입에 관한 법률(화재재해보상법)''에 따라 법령에 열거된 특수건물 소유자는 의무적으로 신체손해배상 특약부 화재보험에 가입해야 한다. 특수건물 범위는 건물 용도·규모별로 다양하며(국·공유 건물 1,000㎡ 이상, 학원 2,000㎡ 이상, 병원·호텔·공연장·학교·공장·16층 이상 아파트 등 3,000㎡ 이상 등 시행령 제2조 별표 기준). 특수건물 화재로 타인이 사망·부상을 입으면 과실 유무와 관계없이 법정 보험금액 범위에서 손해 배상 책임을 지며, 미가입 시 과태료 1,000만원 이하 부과 가능. 일반 화재보험(임의 가입)과 구별되는 강제보험.','계약',array['특수건물 의무보험','신체손해배상 특약부 화재보험','화재재해보상법','특수건물 강제보험','과실 무관 배상'],'cycle2_supp','cycle2_supp','화재로 인한 재해보상과 보험가입에 관한 법률 및 시행령(국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 화재보험 의무가입(easylaw.go.kr); 금융위원회 화재재해보상법 개정 안내(fsc.go.kr)','ai_draft','medium','admin'),
('term','다중이용업소 화재배상책임보험(의무가입)','''다중이용업소의 안전관리에 관한 특별법''에 따라 노래방·PC방·음식점 등 다중이용업소 업주는 화재배상책임보험에 의무 가입해야 한다. 인명피해 사망 1인당 최대 1억5천만원(실손해액이 2천만원 미만이면 2천만원 최저보장), 재산피해 사고 1건당 최대 10억원 보상. 재난 및 안전관리 기본법 제76조의5에 따른 재난배상책임보험 의무가입 대상 20개 업종과 일부 중복 적용. 미가입 시 행정처분(영업정지 등).','계약',array['다중이용업소 화재배상책임보험','의무배상책임보험','재난배상책임보험','화재배상 강제보험','다중이용업소 의무가입'],'cycle2_supp','cycle2_supp','다중이용업소의 안전관리에 관한 특별법(국가법령정보센터 law.go.kr); 행정안전부 재난배상책임보험 운영(mois.go.kr); 재난안전의무보험별 소개(ins24.go.kr)','ai_draft','high','admin'),
('term','의료사고 분쟁조정 절차(한국의료분쟁조정중재원)','''의료사고 피해구제 및 의료분쟁 조정 등에 관한 법률''에 따라 운영되는 한국의료분쟁조정중재원(2012년 설립)을 통한 의료분쟁 해결 절차. 환자·의료기관 일방 신청으로 개시되며, 조정 90일(최대 120일) 내에 처리. 의료사고 조사·감정 후 조정기일에 합의로 조정조서 작성(성립) 또는 조정결정 후 쌍방 동의로 성립. 조정안 20일 내 수락 의사표시 없으면 불성립. 신청 시효는 행위 종료일로부터 10년, 손해·가해자 안 날로부터 3년.','민원',array['의료분쟁 조정','의료분쟁조정중재원','의료사고 배상','의료분쟁 절차','의료사고 피해구제법'],'cycle2_supp','cycle2_supp','의료사고 피해구제 및 의료분쟁 조정 등에 관한 법률(국가법령정보센터 law.go.kr); 한국의료분쟁조정중재원(k-medi.or.kr); 법제처 찾기쉬운 생활법령 의료분쟁(easylaw.go.kr)','ai_draft','high','admin'),
('term','영업배상책임보험(시설·업무 수행 중 제3자 신체·재물 손해 담보)','피보험자가 영업활동(시설 관리·업무 수행) 중 우연한 사고로 제3자에게 신체적 손해나 재물 손해를 입혀 법률상 손해배상책임을 질 때 보험사가 보상하는 손해보험. 임의보험이며 재난배상책임보험보다 보장 범위가 넓다. 하위 종류로는 시설소유관리자배상책임, 생산물배상책임(제조물책임), 개인(일상생활)배상책임, 의료과실배상책임 등이 있다. 보험업법상 손해보험 종목으로 금융위원회가 인가.','보장',array['영업배상책임보험','시설배상책임','생산물배상책임','일상생활배상책임','손해보험 배상책임'],'cycle2_supp','cycle2_supp','법제처 찾기쉬운 생활법령 책임보험(easylaw.go.kr); 손해보험협회 교육센터(edu.knia.or.kr)','ai_draft','high','admin'),
('term','보험계약 부활(효력회복) 절차와 요건(상법 제650조의2)','상법 제650조의2에 따라 보험료 미납으로 해지된 보험계약이 해지환급금 미지급 상태인 경우, 보험계약자는 해지일로부터 3년 이내에 연체 보험료와 이자(평균공시이율+1% 이내)를 납입하고 부활(효력회복)을 청약할 수 있다. 보험회사는 부활 청약 시 다시 심사(고지의무 재적용)하며 승낙 여부를 결정한다. ''자동 실효 약관''(최고 없이 자동 해지)은 상법 제650조·663조 위반으로 무효(대법원 판례).','계약',array['보험계약 부활','효력회복','상법 650조의2','실효 부활 조건','연체보험료 납입'],'cycle2_supp','cycle2_supp','상법 제650조의2(국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 보험계약 효력회복(easylaw.go.kr/CSP/CnpClsMain.laf?csmSeq=526); 보험연구원 주간이슈(kiri.or.kr/PDF/weeklytrend/20240930/trend20240930_3.pdf)','ai_draft','high','admin'),
('term','실손보험 청구서류 표준화(진단서·세부내역서·영수증 기준)','2010년 4월 1일 표준화, 2014년 1월 1일 간소화된 실손의료보험금 청구서류 기준. 입원의료비 청구 시 진단서+진료비 세부내역서+진료비 영수증이 기본이며, 50만원 이하 입원은 진단서 대신 진단명 및 입원기간이 포함된 입퇴원 확인서 또는 진료확인서로 대체 가능. 통원 청구 시 3만원 이하는 청구서+영수증만으로 가능, 3만원 초과~10만원 이하는 진료비 영수증+질병분류기호 기재 처방전으로 가능, 10만원 초과는 진단명 확인 가능 서류(처방전·소견서 등) 추가 제출. 2024년 10월 이후 실손24 전산청구를 선택하면 서류 없이 의료기관이 직접 전송.','민원',array['실손보험 청구서류','진단서 대체 서류','세부내역서','청구서류 표준화','실손 청구 방법'],'cycle2_supp','cycle2_supp','손해보험협회 실손의료보험금 청구서류 표준화 및 통일화 안내(consumer.knia.or.kr/m/consumer/insurance-guide/0202.do)','ai_draft','medium','admin'),
('term','보험금 지급 지연이자(보험업감독규정상 지연 이자율)','보험사가 보험금 청구서류 접수 후 법정 처리기한(통상 3영업일, 조사 필요 시 10영업일, 최대 30영업일) 내에 지급하지 않으면 지연 이자를 부담해야 한다. 지연 이자율은 상법 제54조의 상사법정이율(연 6%) 기준이 판례상 첫 기준으로 적용되며, 이후 소송 진행 시 소송촉진 등에 관한 특례법상 이율(연 12%)이 적용된다. 분쟁조정 신청 시 소멸시효가 중단된다. 단, 정당한 사유(사고 조사·소송 계속 중)가 있으면 지급 지연이 면책될 수 있다.','민원',array['보험금 지연이자','보험금 지급기한','지연 이자율','보험업감독규정','보험금 처리기한'],'cycle2_supp','cycle2_supp','보험업감독업무시행세칙 별표15(law.go.kr); 법제처 찾기쉬운 생활법령 보험금 지급기한(easylaw.go.kr/CSP/CnpClsMain.laf?csmSeq=526); 국가법령정보센터 판례(보험금 지연손해금, law.go.kr)','ai_draft','medium','admin'),
('term','실손보험 청구 시효(3년 소멸시효와 기산점)','실손의료보험금 청구권은 상법 제662조에 따라 3년의 소멸시효가 적용된다. 기산점은 보험사고 발생을 안 날이 아니라 보험금을 청구할 수 있는 날, 즉 진료비 지출일이 원칙. 분쟁조정 신청 시 소멸시효가 중단되며, 조정이 성립하지 않은 날로부터 다시 기산된다. 실무상 오래된 진료비도 3년 이내라면 소급 청구 가능하므로, 설계사가 가입자에게 미청구 진료비 내역 정리를 안내하는 것이 중요.','민원',array['실손보험 청구 소멸시효','보험금 청구 3년','소멸시효 기산점','미청구 보험금','상법 662조'],'cycle2_supp','cycle2_supp','상법 제662조(소멸시효, law.go.kr); 법제처 찾기쉬운 생활법령 분쟁조정 소멸시효 중단(easylaw.go.kr)','ai_draft','high','admin'),
('term','선별급여(예비급여) 본인부담 차등 구조','국민건강보험법상 치료 효과 불확실·경제성 불명확 의료행위를 급여와 비급여 사이 ''선별급여''로 분류하여 본인부담률을 30·50(60)·80·90%까지 높여 급여화한 제도. 보건복지부 고시로 항목별 본인부담률을 달리 지정한다. 실손보험에서는 선별급여 본인부담금도 급여 공제 대상이며, 본인부담상한제 산정에서는 제외된다. 추나요법 등 일부 항목이 선별급여로 편입된 바 있다.','보장',array['선별급여','예비급여','본인부담 차등','급여 비급여 중간','추나요법 선별급여'],'cycle2_supp','cycle2_supp','건강보험심사평가원 본인부담률 안내(hira.or.kr); 국민건강보험 요양급여의 기준에 관한 규칙 별표2 선별급여목록(law.go.kr/LSW/flDownload.do?flSeq=151430065)','ai_draft','medium','admin'),
('term','종신형 연금보험 비과세 요건 (보증기간 기대여명 이내)','세제비적격 연금보험이 보험차익 비과세 혜택을 받으려면 종신형 수령 시 1) 55세 이후 사망 시까지 연금 수령, 2) 연금 외 형태로 지급받지 않을 것, 3) 보증기간이 통계청 고시 성별·연령별 기대여명 연수 이내일 것, 4) 계약자=피보험자=수익자 동일, 5) 중도해지 불가 요건을 모두 충족해야 한다(소득세법 시행령 제25조). 기대여명보다 보증기간이 짧거나 같아야 하며, 초과 설정 시 비과세 요건 미충족으로 이자소득세(15.4%)가 과세된다.','세제',array['종신형연금','비과세요건','기대여명','보증기간','소득세법시행령25조','세제비적격'],'cycle2_supp','cycle2_supp','소득세법 시행령 제25조(국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 연금보험 항목(easylaw.go.kr/CSP/CnpClsMain.laf?csmSeq=2056)','ai_draft','high','admin'),
('term','연금수령한도 초과 인출 — 기타소득세 16.5% 분리과세','연금계좌(연금저축·IRP)에서 연금수령한도를 초과해 인출하면 초과분은 연금소득이 아닌 기타소득으로 분류돼 16.5%(지방소득세 포함) 세율로 분리과세된다(소득세법 제21조 제1항 제21호, 시행령 제40조의2). 연금수령한도 = 과세기간 개시일 현재 연금계좌 평가액 ÷ (11 - 연금수령연차) × 120%이며, 연금수령연차 11년 이상이면 한도 제한이 없다.','세제',array['연금수령한도','기타소득세','분리과세','16.5%','소득세법','연금외수령'],'cycle2_supp','cycle2_supp','소득세법 시행령 제40조의2(국가법령정보센터 law.go.kr); 국세청 연금소득의 범위(nts.go.kr/nts/cm/cntnts/cntntsView.do?mi=6449&cntntsId=7885)','ai_draft','high','admin'),
('term','이연퇴직소득 연금수령 시 퇴직소득세 감면 (10년 이내 30%, 11년 차 이후 40%)','퇴직소득을 IRP 등 연금계좌에 이전해 연금으로 분할 수령하면 이연퇴직소득에 대한 퇴직소득세가 감면된다. 연금수령 연차 10년 이하는 퇴직소득세율의 70% 납부(세금 30% 감면), 10년 초과는 60% 납부(40% 감면) 적용(소득세법 시행령 제202조의3). 이는 일시금 퇴직소득세에 비해 최대 40% 절세 효과이며, 과세이연과 분리돼 계산된다.','세제',array['이연퇴직소득','퇴직소득세감면','IRP연금수령','30%감면','40%감면','과세이연'],'cycle2_supp','cycle2_supp','소득세법 시행령 제202조의3(국가법령정보센터 law.go.kr); 국세청 퇴직소득세의 이연 안내(nts.go.kr/nts/cm/cntnts/cntntsView.do?mi=6602&cntntsId=7882)','ai_draft','medium','admin'),
('term','즉시연금 비과세 과세 논쟁 및 2013년 세법 개정 경과','즉시연금(목돈 일시납 후 즉시 연금 지급)은 2013년 2월 14일 이전 가입자에게는 금액 제한 없이 비과세였다. 이후 소득세법 시행령 제25조 개정으로 상속형 즉시연금은 납입보험료 1억 원 초과분에 대해 이자소득세 과세로 전환됐다. 종신형 즉시연금은 종신형 비과세 요건 충족 시 비과세 유지, 상속형은 1억 원 이하 비과세, 초과 시 이자소득세(15.4%) 과세(소득세법 시행령 제25조). 이 개정은 2013년 2월 15일부터 시행됐다.','세제',array['즉시연금','비과세과세논쟁','2013년세법개정','상속형즉시연금','1억원한도'],'cycle2_supp','cycle2_supp','소득세법 시행령 제25조(국가법령정보센터 law.go.kr); 보험연구원 ''연금보험의 비과세기준 개정 필요성과 시사점''(kiri.or.kr/report/downloadFile.do?docId=681)','ai_draft','medium','admin'),
('term','연금계좌 가입일 5년 경과 요건 — 이연퇴직소득 예외','연금계좌에서 연금수령으로 인정받으려면 가입일로부터 5년이 경과해야 하지만, 이연퇴직소득(퇴직소득이 직접 연금계좌로 입금된 금액)이 계좌에 있는 경우 5년 경과 요건이 면제된다(소득세법 시행령 제40조의2). 직장 퇴직 후 IRP에 수령된 퇴직금은 가입 즉시 연금 개시 요건을 충족할 수 있다.','세제',array['연금계좌','5년경과요건','이연퇴직소득','예외','소득세법시행령40조의2'],'cycle2_supp','cycle2_supp','소득세법 시행령 제40조의2(국가법령정보센터 law.go.kr); 법제처 찾기쉬운 생활법령 퇴직연금 항목(easylaw.go.kr/CSP/CnpClsMain.laf?csmSeq=2056)','ai_draft','high','admin'),
('term','연금저축 세액공제 한도 600만 원, IRP 합산 900만 원 (2023년 상향)','2023년부터 연금계좌 세액공제 납입한도가 상향됐다. 연금저축 단독 최대 600만 원, 연금저축+IRP 합산 900만 원까지 세액공제 대상이다(소득세법 제59조의3). 세액공제율은 종합소득금액 4,500만 원(근로소득만 있으면 총급여 5,500만 원) 이하 16.5%, 초과 13.2%다. 2022년 이전 한도(400만 원/700만 원)에서 각각 200만 원씩 상향됐다.','세제',array['연금저축세액공제','IRP합산900만원','600만원한도','소득세법59조의3','2023년개정'],'cycle2_supp','cycle2_supp','소득세법 제59조의3(국가법령정보센터 law.go.kr); 국세청 연금계좌 세액공제 한도 안내(nts.go.kr/nts/cm/cntnts/cntntsView.do?cntntsId=7875)','ai_draft','high','admin'),
('term','ISA 만기자금 연금계좌 전환 시 추가 세액공제 300만 원','개인종합자산관리계좌(ISA)를 만기 또는 의무보유기간 경과 후 해지해 연금계좌(연금저축·IRP)로 이전하면, 이전 금액의 10%(최대 300만 원)를 추가 세액공제받을 수 있다(소득세법 제59조의3 제6항). ISA 만기일 또는 해지일로부터 60일 이내 이전해야 하며, 기존 연금계좌 세액공제 한도(연 900만 원) 외 추가 납입한도도 ISA 이전 금액만큼 증가한다.','세제',array['ISA만기연금전환','추가세액공제300만원','소득세법59조의3','연금계좌이전'],'cycle2_supp','cycle2_supp','소득세법 제59조의3 제6항(국가법령정보센터), 국세청 연금계좌 세액공제 한도 안내(nts.go.kr)','ai_draft','high','admin'),
('term','연금계좌 부득이한 인출 — 저율 연금소득세 적용','연금계좌에서 중도 인출 시 원칙적으로 기타소득세 16.5%가 부과되나, 소득세법에서 정한 ''부득이한 사유''(천재지변, 가입자 사망, 해외이주, 파산·개인회생 개시, 가입자 또는 부양가족 3개월 이상 요양, 특별재난지역 재난 피해 등)에 해당하면 연령별 저율 연금소득세(55~69세 5.5%, 70~79세 4.4%, 80세 이상 3.3%)가 적용된다. 사유 확인일로부터 6개월 이내 인출해야 한다. IRP의 경우 요양 요건이 더 엄격(6개월 이상, 연간 총급여의 12.5% 이상)할 수 있으므로 상품별 확인이 필요하다.','세제',array['연금계좌부득이한인출','저율과세','연금소득세','중도인출예외','기타소득세면제'],'cycle2_supp','cycle2_supp','소득세법 시행령(국가법령정보센터), 국세청 연금소득 범위 안내(nts.go.kr), 보험연구원 KIRI 리포트','ai_draft','medium','admin'),
('term','연금보험 계약자 변경과 증여세 — 연금개시 전후 과세 차이','보험료를 납입한 계약자와 수익자가 다른 경우 수익자가 연금 수령 시 증여세가 과세된다. 연금개시 전 계약자 변경 시 변경 후 계약자에게 증여세가 과세되며, 개시 후 연금 수령자가 계약자와 다를 경우 수령자에게 과세된다(상속세 및 증여세법 제34조). 증여재산가액은 미래 연금액을 현재가치로 할인한 금액과 해지환급금 중 큰 금액으로 평가한다. 계약자 변경 시 비과세 기산점은 변경일로 재산정된다(단, 사망으로 인한 변경은 최초 납입일 기준 유지).','세제',array['연금보험계약자변경','증여세','연금개시전후','수익자다른경우','상속세및증여세법'],'cycle2_supp','cycle2_supp','국세청 서면-2020-상속증여-3039(CaseNote), 상속세 및 증여세법 제34조(국가법령정보센터), 국세청 홈택스 사전-2019-법령해석재산 질의회신','ai_draft','high','admin'),
('term','연금개시 전·후 사망 시 상속재산 평가 차이','연금개시 전 사망 시 보험계약은 상속재산으로서 상속개시 당시 해지환급금 상당액으로 평가된다(상속세 및 증여세법 제8조 및 국세청 사전-2019-법령해석재산-0378). 연금개시 후 사망 시 이미 수령한 연금은 원칙상 과세 완료 소득이며, 계속 수령 예정인 연금 권리는 유기정기금 또는 종신정기금 평가방법(상속세 및 증여세법 시행령 제62조)을 적용한다. 국민연금에서 지급되는 유족연금은 상속세 과세 대상에서 제외된다.','세제',array['연금개시전사망','연금개시후사망','상속재산평가','유기정기금평가','해지환급금평가'],'cycle2_supp','cycle2_supp','상속세 및 증여세법 제8조·시행령 제62조(국가법령정보센터), 국세청 사전-2019-법령해석재산-0378','ai_draft','medium','admin'),
('term','유기정기금 평가 — 연금보험 상속·증여세 산출 기준','연금을 일정 기간 동안 수령하는 유기정기금은 상속·증여세 산출 시 매 회 수령액에 기간에 따른 할인율을 적용한 현재가치로 평가한다(상속세 및 증여세법 제65조, 시행령 제62조). 1년분 정기금액의 20배를 한도로 한다. 종신지급형 즉시연금의 경우 최저보증기간이 잔여 기대수명보다 길면 유기정기금 평가, 짧으면 종신정기금 평가 방식을 적용한다.','세제',array['유기정기금평가','상속세증여세','연금보험상속','상속세및증여세법65조','종신정기금'],'cycle2_supp','cycle2_supp','상속세 및 증여세법 제65조·시행령 제62조(국가법령정보센터), 국세청 서면-2019-상속증여-0012(CaseNote)','ai_draft','high','admin'),
('term','변액보험 특별계정 — 일반계정 분리 운용 (보험업법 제108조)','변액보험 보험료 중 저축보험료(적립보험료)는 일반계정과 분리된 특별계정에서 운용된다. 보험업법 제108조에 따라 보험회사는 변액보험계약 준비금에 상당하는 자산을 특별계정으로 설정·운용해야 하며, 특별계정 자산과 일반계정 자산은 분리 운용된다. 다만 계약자 자산 보호(파산 시 계약자 우선 귀속)는 보험업법 제108조가 아닌 보험업법 제119조 등 별도 조항에 근거하므로, 특별계정 설정이 곧 파산 완전 격리를 의미하지는 않는다.','계약',array['변액보험특별계정','일반계정분리','보험업법108조','특별계정보호','계약자적립금'],'cycle2_supp','cycle2_supp','보험업법 제108조(국가법령정보센터, LBOX 법령), CaseNote 금융위원회·금감원 일반계정·특별계정 보상책임 질의','ai_draft','medium','admin'),
('term','변액보험 최저사망보험금보증 (GMDB)','최저사망보험금보증(Guaranteed Minimum Death Benefit, GMDB)은 변액보험에서 투자 성과와 무관하게 피보험자 사망 시 최소한 기납입보험료 이상의 사망보험금을 지급하도록 보험회사가 보증하는 제도다. 보험업감독규정 제7-60조 제7호에 따라 변액보험(연금보험 제외)은 최저사망보험금 설정이 의무다. 투자 원금 손실 시에도 사망보험금은 기납입보험료 수준으로 유지된다.','보장',array['GMDB','최저사망보험금보증','변액보험최저보증','보험업감독규정7-60조','사망보험금보증'],'cycle2_supp','cycle2_supp','보험업감독규정 제7-60조 제7호(국가법령정보센터), 보험연구원 ''변액연금 최저보증 및 사업비 부과 현황 조사'' 2018(kiri.or.kr)','ai_draft','high','admin'),
('term','최저연금적립금보증 (GMAB)','최저연금적립금보증(Guaranteed Minimum Accumulation Benefit, GMAB)은 변액연금보험의 연금개시시점(제1보험기간 만기)에 계약자적립금이 기납입보험료 이하로 하락해도 약정된 최저보증금액 이상을 연금재원으로 보장하는 제도다. 2002년 국내 변액연금 판매 개시와 함께 도입됐다. 보증비용은 매월 특별계정에서 차감된다. 2016년 이후 GMAB 미보증형 상품도 허용됐으며 이 경우 연금개시 시점에 원본 손실 가능성이 있다.','보장',array['GMAB','최저연금적립금보증','변액연금보험','연금개시시점보증','원본손실가능'],'cycle2_supp','cycle2_supp','보험연구원 ''변액연금 최저보증 및 사업비 부과 현황 조사'' 2018(kiri.or.kr), KCI 학술논문 ''변액연금GMAB 미보증형 생명보험 상품의 법적용에 관한 연구''','ai_draft','high','admin'),
('term','최저종신중도인출보증 (GLWB)','최저종신인출금보증(Guaranteed Lifetime Withdrawal Benefit, GLWB)은 변액연금에서 계약자적립금이 0이 될 때까지 또는 사망 시까지 매년·매월 일정 금액을 중도 인출할 수 있도록 보험회사가 보장하는 제도다. 국내에서는 2008년 말 일부 생보사가 판매를 개시했으나 초기 실제 판매 규모는 제한적이었다. 특별계정에서 계속 투자되면서 인출이 가능하며, 사망 시 잔여 적립금이 있으면 상속인에게 환급된다. 보증비용은 특별계정에서 차감된다.','보장',array['GLWB','최저종신인출보증','변액연금','종신인출보장','2008년도입'],'cycle2_supp','cycle2_supp','보험연구원 KIRI ''변액보험 최저보증 현황조사'', 보험금융연구 제22권 제2호(2011)(kiri.or.kr)','ai_draft','medium','admin'),
('term','공시이율과 최저보증이율 — 금리연동형 보험 이율 구조','공시이율은 보험사가 운용자산이익률·외부지표금리(국고채·회사채 등 가중이동평균)를 기반으로 매월 공시하는 이율이다. 최저보증이율은 시장금리가 아무리 하락해도 보험사가 보장하는 최저 적립이율이다. 보험업감독규정 제6-12조에 따라 공시기준이율은 보장성의 경우 운용자산이익률×35% + 외부지표금리×65%, 저축·연금의 경우 운용자산이익률×30% + 외부지표금리×70%로 산출한다. 적용공시이율은 공시기준이율의 80~120% 범위 내에서 결정된다.','계약',array['공시이율','최저보증이율','금리연동형보험','보험업감독규정6-12조','공시기준이율'],'cycle2_supp','cycle2_supp','보험업감독규정 제6-12조(국가법령정보센터), DB생명 공시기준이율·공시이율 안내(idblife.com)','ai_draft','high','admin'),
('term','변액보험 펀드변경 — 연 12회 무료, 초과 시 수수료','변액보험 가입자는 특별계정 내 투자 펀드를 일반적으로 연 12회까지 무료로 변경할 수 있다. 12회 초과 변경 시 수수료가 부과되며, 구체적 기준은 보험사별 약관에 따른다. 연 12회 무료는 법령상 강제 기준이 아니라 업계 일반 관행이므로 가입 상품 약관 확인이 필요하다. 펀드변경은 투자위험을 조정하는 핵심 수단으로 보험업감독규정 및 생명보험협회 공시 기준에 따라 변액보험공시실에서 자산운용옵션(펀드변경) 현황을 공시해야 한다.','계약',array['변액보험펀드변경','연12회무료','자산운용옵션','특별계정','생명보험협회공시'],'cycle2_supp','cycle2_supp','생명보험협회 변액보험공시실(klia.or.kr) / 보험업감독규정(국가법령정보센터 law.go.kr)','ai_draft','medium','admin');
